import java.io.ByteArrayInputStream;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import org.w3c.dom.Document;
import org.xml.sax.InputSource;

public class SoapService {
    public static void main(String[] args) throws Exception {
        // Initialize the DocumentBuilderFactory and DocumentBuilder
        DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
        DocumentBuilder db = dbf.newDocumentBuilder();

        // Parse the incoming SOAP message using the DocumentBuilder
        InputSource is = new InputSource(new ByteArrayInputStream("<?xml version=\"1.0\" encoding=\"UTF-8\"?><soap:Envelope xmlns:soap=\"http://www.w3.org/2003/05/soap-envelope/\"><soap:Body><m:GetLastTradePrice xmlns:m=\"http://www.example.com\"><symbol>IBM</symbol></m:GetLastTradePrice></soap:Body></soap:Envelope>".getBytes("UTF-8")));
        Document doc = db.parse(is);

        // Handle the complex XML structure with nested entities
        NodeList nodes = doc.getElementsByTagName("m:GetLastTradePrice");
        for (int i = 0; i < nodes.getLength(); i++) {
            Node node = nodes.item(i);
            if (node.getNodeType() == Node.ELEMENT_NODE) {
                Element element = (Element) node;
                String symbol = element.getElementsByTagName("symbol").item(0).getTextContent();
                System.out.println("Symbol: " + symbol);
            }
        }
    }
}